-- ============================================================
-- FINAL WIPE AND RELOAD
-- Clears all inquiries and reloads them with serial_no set
-- to the EXACT S.No from the Excel tracker — guarantees the
-- app order matches the sheet order perfectly.
-- Run in: Supabase Dashboard → SQL Editor
-- WARNING: Deletes all current inquiry data (files, architects,
-- fabricators, team members are also cleared and reloaded)
-- ============================================================

-- Step 1: Clear everything (inquiry_files cascade automatically)
DELETE FROM public.inquiries;
DELETE FROM public.architects;
DELETE FROM public.fabricators;
DELETE FROM public.schueco_team;

-- Step 2: Unique constraints (safe if already exist)
DROP INDEX IF EXISTS architects_name_unique;
DROP INDEX IF EXISTS fabricators_name_unique;
DROP INDEX IF EXISTS schueco_team_name_unique;
CREATE UNIQUE INDEX architects_name_unique   ON public.architects   (lower(trim(name)));
CREATE UNIQUE INDEX fabricators_name_unique  ON public.fabricators  (lower(trim(name)));
CREATE UNIQUE INDEX schueco_team_name_unique ON public.schueco_team (lower(trim(name)));

-- Step 3: Reload architects
ON CONFLICT DO NOTHING;

-- Step 4: Reload fabricators
ON CONFLICT DO NOTHING;

-- Step 5: Reload team
ON CONFLICT DO NOTHING;

-- Step 6: Reload all inquiries — serial_no EXPLICITLY set to the
-- Excel's S.No column, so app order matches the sheet exactly


-- Step 7: Reset the auto-increment sequence so the NEXT new
-- inquiry registered in the app gets serial_no 182
DO $$
BEGIN
  DROP SEQUENCE IF EXISTS inquiries_serial_seq;
  EXECUTE format('CREATE SEQUENCE inquiries_serial_seq START WITH %s', 182);
END $$;
ALTER TABLE public.inquiries ALTER COLUMN serial_no SET DEFAULT nextval('inquiries_serial_seq');
ALTER SEQUENCE inquiries_serial_seq OWNED BY public.inquiries.serial_no;